        &lt;path d="M0,0 L6,3 L0,6 Z" fill="#333" /&gt;
      &lt;/marker&gt;
      &lt;marker id="arrowhead-up" markerWidth="6" markerHeight="6" refX="3" refY="3" orient="auto"&gt;
