    &lt;text x="${positionToX(currentLocationPos)}" y="${centerY + labelOffsetBelow}" text-anchor="middle" 
          font-size="${labelFontSize}" fill="#333"&gt;Current location&lt;/text&gt;
    &lt;line x1="${positionToX(currentLocationPos)}" x2="${positionToX(currentLocationPos)}" 
